function targetFingerprint(target: HTMLElement) {
  let testid: string | null = null;
  let text = '';
  for (let n: HTMLElement | null = target; n && n !== document.body; n = n.parentElement) {
    if (!testid && n.getAttribute) testid = n.getAttribute('data-testid');
    if (!text && n.textContent) text = (n.textContent || '').trim().slice(0, 40);
    if (testid) break;
  }
  return { testid, text };
}

function findNextState(currentSeq: number, target: HTMLElement, eventType: string = 'click'): StateRec | null {
  const { testid, text } = targetFingerprint(target);
  // Pass 1: exact match for the requested event type forward in the graph
  for (const s of STATES) {
    if (s.seq <= currentSeq) continue;
    const t = s.trigger || ({} as StateRec['trigger']);
    if (t.type !== eventType) continue;
    const tt = (t as { target?: { testid?: string | null; text?: string | null } }).target || {};
    if (testid && (t.testid === testid || tt.testid === testid)) return s;
    if (text && t.text && (t.text === text || t.text.indexOf(text.slice(0, 16)) === 0)) return s;
    if (text && tt.text && (tt.text === text || tt.text.indexOf(text.slice(0, 16)) === 0)) return s;
  }
  // Pass 2: any event type forward
  for (const s of STATES) {
    if (s.seq <= currentSeq) continue;
    const t = s.trigger || ({} as StateRec['trigger']);
    const tt = (t as { target?: { testid?: string | null; text?: string | null } }).target || {};
    if (testid && (t.testid === testid || tt.testid === testid)) return s;
    if (text && t.text && (t.text === text || t.text.indexOf(text.slice(0, 16)) === 0)) return s;
    if (text && tt.text && (tt.text === text || tt.text.indexOf(text.slice(0, 16)) === 0)) return s;
  }
  // Pass 3: same fingerprint, starting from beginning (wrap)
  if (eventType !== 'click') {
    for (const s of STATES) {
      const t = s.trigger || ({} as StateRec['trigger']);
      const tt = (t as { target?: { testid?: string | null; text?: string | null } }).target || {};
      if (testid && (t.testid === testid || tt.testid === testid)) return s;
    }
  }
  return null;
}

// Return the next state AND any immediate trailing frames captured for the same
// click event. v2 records frameIndex/totalFrames; we group consecutive frames
// from the same session whose trigger target matches AND whose frameIndex is the
// expected next-in-sequence value.
function findClickSequence(currentSeq: number, target: HTMLElement): StateRec[] {
  const first = findNextState(currentSeq, target);
  if (!first) return [];
  const total = first.totalFrames || 1;
  if (total <= 1) return [first];
  const sequence = [first];
  const firstTrig = first.trigger || ({} as StateRec['trigger']);
  const firstTid = firstTrig.target?.testid || firstTrig.target?.text || null;
  let expected = (first.frameIndex || 1) + 1;
  for (const s of STATES) {
    if (s.seq <= first.seq) continue;
    if (s.sid !== first.sid) break;
    const st = s.trigger || ({} as StateRec['trigger']);
    const tid = st.target?.testid || st.target?.text || null;
    if (st.type === 'click' && tid && firstTid && tid === firstTid && s.frameIndex === expected) {
      sequence.push(s);
      expected += 1;
      if (sequence.length >= total) break;
    } else if (sequence.length === 1) {
      // First trailing frame isn't a match → not part of this click sequence
      break;
    }
  }
  return sequence;
}

function mountCharts(host: HTMLElement, roots: Root[]) {
  host.querySelectorAll<HTMLElement>('[data-element="canvasArea"]').forEach((slot) => {
    const rect = slot.getBoundingClientRect();
    const isLadder = !!slot.closest('[data-testid="ladder-chart-container"]') ||
      !!slot.closest('[data-testid="ladder-timeout-wrapper"]') ||
      (rect.height > 0 && rect.height / Math.max(1, rect.width) > 1.2);
    slot.replaceChildren();
    if (isLadder) {
      // Price ladders aren't candlestick charts. Show the captured PNG so the
      // axis labels and grid render correctly. Bid/ask size bars and the
      // hover "Buy limit"/"Sell limit" pill aren't in captures; hand-build later.
      const img = document.createElement('img');
      img.src = '/chart-fixtures/composite-01.png';
      img.alt = '';
      img.style.cssText = 'position:absolute;inset:0;width:100%;height:100%;display:block;object-fit:fill;pointer-events:none;z-index:0;';
      img.onerror = () => { img.style.display = 'none'; };
      slot.appendChild(img);
      return;
    }
    const root = createRoot(slot);
    root.render(<CandlestickChart />);
    roots.push(root);
  });
}

function markHandled(ev: Event) { (ev as Event & { __rhHandled?: boolean }).__rhHandled = true; }

function detectSymbol(near: HTMLElement): string | null {
  const widget = near.closest('section[data-testid^="widget-"]') || document;
  const marquee = widget.querySelector('[data-testid="instrument-marquee-button"]');
  if (!marquee) return null;
  // Marquee text is "<TICKER>$<price><delta>" — take the leading alpha sequence
  const m = (marquee.textContent || '').trim().match(/^[A-Z]{1,5}/);
  return m ? m[0] : null;
}
function detectExpiration(near: HTMLElement): string | null {
  const widget = near.closest('section[data-testid^="widget-"]') || document;
  // Expiration dropdown text like "Exp May 15 (4D)"
  const buttons = widget.querySelectorAll('button');
  for (const b of Array.from(buttons)) {
    const t = (b.textContent || '').trim();
    const m = t.match(/^Exp\s+([A-Za-z]+)\s+(\d{1,2})\b/);
    if (m) {
      const mon = { Jan: '1', Feb: '2', Mar: '3', Apr: '4', May: '5', Jun: '6', Jul: '7', Aug: '8', Sep: '9', Oct: '10', Nov: '11', Dec: '12' } as Record<string, string>;
      return (mon[m[1]] || '?') + '/' + m[2];
    }
  }
  return null;
}

function wireInteractivity(host: HTMLElement) {
  // 1. role=tab — swap aria-selected, show/hide aria-controls panel
  host.querySelectorAll<HTMLElement>('[role="tab"]').forEach((tab) => {
    const t = tab as HTMLElement & { __rhWired?: boolean };
    if (t.__rhWired) return;
    t.__rhWired = true;
    t.addEventListener('click', (ev) => {
      markHandled(ev);
      ev.stopPropagation();
      const tablist = t.closest('[role="tablist"]') || t.parentElement;
      if (!tablist) return;
      tablist.querySelectorAll<HTMLElement>('[role="tab"]').forEach((sib) => {
        const on = sib === t;
        sib.setAttribute('aria-selected', on ? 'true' : 'false');
        const tid = sib.getAttribute('aria-controls');
        if (tid) {
          const panel = document.getElementById(tid);
          if (panel) panel.hidden = !on;
        }
      });
    }, true);
  });

  // 2. Segmented button groups — siblings where one is highlighted via inline bg2 color
  const seen = new WeakSet<HTMLElement>();
  host.querySelectorAll<HTMLElement>('button').forEach((btn) => {
    const parent = btn.parentElement;
    if (!parent || seen.has(parent)) return;
    const sibs = Array.from(parent.children).filter((c) => c.tagName === 'BUTTON') as HTMLElement[];
    if (sibs.length < 2 || sibs.length > 4) return;
    const hasSelected = sibs.some((s) => /var\(--colors-neutral-bg2\)/.test(s.getAttribute('style') || ''));
    if (!hasSelected) return;
    seen.add(parent);
    sibs.forEach((b) => {
      const bw = b as HTMLElement & { __rhWired?: boolean };
      if (bw.__rhWired) return;
      bw.__rhWired = true;
      bw.addEventListener('click', (ev) => {
        markHandled(ev);
        ev.stopPropagation();
        sibs.forEach((s) => {
          const on = s === bw;
          const style = s.getAttribute('style') || '';
          const cleaned = style.replace(/background-color\s*:[^;]+;?/g, '');
          s.setAttribute('style', cleaned + ';background-color: ' + (on ? 'var(--colors-neutral-bg2)' : 'var(--colors-neutral-transparent)') + ';');
        });
      }, true);
    });
  });

  // 3. aria-expanded toggles (comboboxes, dropdown buttons)
  host.querySelectorAll<HTMLElement>('[aria-expanded]').forEach((el) => {
    const e = el as HTMLElement & { __rhWired?: boolean };
    if (e.__rhWired) return;
    e.__rhWired = true;
    e.addEventListener('click', (ev) => {
      markHandled(ev);
      ev.stopPropagation();
      const cur = e.getAttribute('aria-expanded') === 'true';
      e.setAttribute('aria-expanded', cur ? 'false' : 'true');
    }, true);
  });

  // 4. +/- steppers — Plus/Minus icon inside a button drives nearest numeric input
  host.querySelectorAll<HTMLElement>(
    '[data-testid="icon-Plus16"],[data-testid="icon-Plus8"],[data-testid="icon-Minus8"],[data-testid="icon-Minus16"]'
  ).forEach((icon) => {
    const btn = (icon.closest('button') || icon.closest('[role="button"]')) as HTMLElement | null;
    if (!btn) return;
    const b = btn as HTMLElement & { __rhWired?: boolean };
    if (b.__rhWired) return;
    b.__rhWired = true;
    const isPlus = (icon.getAttribute('data-testid') || '').startsWith('icon-Plus');
    b.addEventListener('click', (ev) => {
      markHandled(ev);
      ev.stopPropagation();
      const scope = b.closest('form') || b.parentElement?.parentElement || b.parentElement;
      const input = scope?.querySelector('input[type="number"], input[inputmode="numeric"], input[role="spinbutton"], [contenteditable="true"]') as HTMLInputElement | HTMLElement | null;
      if (!input) return;
      const delta = isPlus ? 1 : -1;
      if (input instanceof HTMLInputElement) {
        let v = Number(input.value) || 0;
        v = Math.max(0, v + delta);
        input.value = String(v);
        input.dispatchEvent(new Event('input', { bubbles: true }));
      } else {
        let v = Number(input.textContent) || 0;
        v = Math.max(0, v + delta);
        input.textContent = String(v);
      }
    }, true);
  });

  // 5. Plain buttons / checkboxes — give them a visible click "active" pulse so the
  // user feels feedback even when there's no recorded state change.
  host.querySelectorAll<HTMLElement>('button,[role="button"],[role="checkbox"],[role="switch"]').forEach((el) => {
    const e = el as HTMLElement & { __rhPulseWired?: boolean };
    if (e.__rhPulseWired) return;
    e.__rhPulseWired = true;
    e.addEventListener('pointerdown', () => {
      e.style.transition = 'transform 80ms ease, opacity 80ms ease';
      e.style.transform = 'scale(0.97)';
      e.style.opacity = '0.85';
    }, true);
    const restore = () => { e.style.transform = ''; e.style.opacity = ''; };
    e.addEventListener('pointerup', restore, true);
    e.addEventListener('pointerleave', restore, true);
    e.addEventListener('pointercancel', restore, true);
  });

  // 6. role=checkbox / aria-checked toggle
  host.querySelectorAll<HTMLElement>('[role="checkbox"],[role="switch"]').forEach((el) => {
    const e = el as HTMLElement & { __rhWired?: boolean };
    if (e.__rhWired) return;
    e.__rhWired = true;
    e.addEventListener('click', (ev) => {
      markHandled(ev);
      const cur = e.getAttribute('aria-checked') === 'true';
      e.setAttribute('aria-checked', cur ? 'false' : 'true');
    }, true);
  });

  // 6b. Chain / Simulated Returns tab toggle — Robinhood uses LABEL elements
  // (segmented radio toggles), not buttons. Match by exact text.
  for (const tab of Array.from(host.querySelectorAll<HTMLElement>('label, button'))) {
    const txt = (tab.textContent || '').trim();
    if (txt !== 'Chain' && txt !== 'Simulated Returns') continue;
    const b = tab as HTMLElement & { __rhTabWired?: boolean };
    if (b.__rhTabWired) continue;
    b.__rhTabWired = true;
    b.addEventListener('click', (ev) => {
      ev.preventDefault();
      ev.stopPropagation();
      markHandled(ev);
      const opener = (window as Window & typeof globalThis & { __rhSetSimReturns?: (v: boolean) => void }).__rhSetSimReturns;
      if (opener) opener(txt === 'Simulated Returns');
    }, true);
  }

  // 7. Chain row hover — each visual row is split across multiple [role="row"]
  // elements (left frozen pane, scrolling middle, pinned Ask column). Group them
  // by the leading strike in data-cell-id so the highlight spans the full row.
  const chainBody = host.querySelector('[data-testid="focused-chain-body-container"]') as HTMLElement | null;
  if (chainBody) {
    const rowsByStrike = new Map<string, HTMLElement[]>();
    chainBody.querySelectorAll<HTMLElement>('[role="row"]').forEach((row) => {
      const cell = row.querySelector('[data-cell-id]');
      const cid = cell?.getAttribute('data-cell-id') || '';
      const strike = cid.split('_')[0];
      if (!strike) return;
      if (!rowsByStrike.has(strike)) rowsByStrike.set(strike, []);
      rowsByStrike.get(strike)!.push(row);
      row.setAttribute('data-rh-strike', strike);
      row.style.transition = 'background-color 200ms cubic-bezier(0.05, 0.39, 0.42, 0.94)';
    });
    // Real Robinhood tokens (extracted from live page):
    //   --colors-neutral-bg2 = rgba(255,255,255,0.10)  → row hover bg
    //   --colors-extended-cosmonaut = #8761ec          → selected accent
    const hoverBg = 'rgba(255, 255, 255, 0.10)';
    const selBg   = 'rgba(135, 97, 236, 0.18)';
    const easing  = 'cubic-bezier(0.05, 0.39, 0.42, 0.94)';
    const wired = chainBody as HTMLElement & { __rhChainHoverWired?: boolean };
    if (!wired.__rhChainHoverWired) {
      wired.__rhChainHoverWired = true;
      let activeStrike: string | null = null;
      const paint = (strike: string | null, bg: string) => {
        if (!strike) return;
        for (const r of rowsByStrike.get(strike) || []) {
          if (r.hasAttribute('data-rh-selected')) continue;
          r.style.backgroundColor = bg;
        }
      };
      chainBody.addEventListener('pointerover', (ev) => {
        const t = ev.target as HTMLElement | null;
        const row = t?.closest('[role="row"][data-rh-strike]') as HTMLElement | null;
        const strike = row?.getAttribute('data-rh-strike') || null;
        if (strike === activeStrike) return;
        if (activeStrike) paint(activeStrike, '');
        activeStrike = strike;
        if (activeStrike) paint(activeStrike, hoverBg);
      }, true);
      chainBody.addEventListener('pointerleave', () => {
        if (activeStrike) paint(activeStrike, '');
        activeStrike = null;
      }, true);
      // Expose selection helper for the Ask-pill click handler below.
      (chainBody as HTMLElement & { __rhMarkSelected?: (s: string) => void }).__rhMarkSelected = (strike: string) => {
        for (const [s, rows] of rowsByStrike) {
          for (const r of rows) {
            if (s === strike) {
              r.setAttribute('data-rh-selected', '1');
              r.style.backgroundColor = selBg;
            } else if (r.hasAttribute('data-rh-selected')) {
              r.removeAttribute('data-rh-selected');
              r.style.backgroundColor = '';
            }
          }
        }
      };
    }

    // Row-body click → toggle the expanded Stats/Greeks panel.
    // The expansion is rendered as an ABSOLUTELY-POSITIONED child of the chain
    // body (which we make position:relative) so it scrolls together with the
    // rows naturally — no JS scroll sync needed, no wobble. Spacers in each
    // pane push the rows below down so nothing overlaps.
    const EXPAND_H = 300;
    chainBody.style.position = chainBody.style.position || 'relative';
    const clearExpansion = (): void => {
      host.querySelectorAll('[data-rh-expand-spacer]').forEach((s) => s.remove());
      host.querySelectorAll('[data-rh-expand-mount]').forEach((s) => s.remove());
    };
    const insertSpacersAndMount = (strike: string, row: HTMLElement): HTMLElement | null => {
      const rows = host.querySelectorAll<HTMLElement>('[data-rh-strike="' + strike + '"]');
      rows.forEach((r) => {
        const wrap = r.parentElement?.parentElement;
        if (!wrap || !wrap.parentElement) return;
        const spacer = document.createElement('div');
        spacer.setAttribute('data-rh-expand-spacer', strike);
        spacer.style.cssText = 'block-size:' + EXPAND_H + 'px;inline-size:100%;flex-shrink:0;';
        wrap.parentElement.insertBefore(spacer, wrap.nextSibling);
      });
      // Mount overlay — sits at the row's bottom edge, spans the chain body width,
      // scrolls with the chain body since it is absolutely-positioned inside it.
      const cbRect = chainBody.getBoundingClientRect();
      const rowRect = row.getBoundingClientRect();
      const topInBody = rowRect.bottom - cbRect.top + chainBody.scrollTop;
      const mount = document.createElement('div');
      mount.setAttribute('data-rh-expand-mount', strike);
      mount.style.cssText = 'position:absolute;left:0;right:0;top:' + topInBody + 'px;block-size:' + EXPAND_H + 'px;z-index:5;background:#202020;overflow:hidden;';
      chainBody.appendChild(mount);
      return mount;
    };

    chainBody.addEventListener('click', (ev) => {
      const t = ev.target as HTMLElement | null;
      if (!t) return;
      if (t.closest('button[aria-describedby="order-form-flyover"]')) return;
      const row = t.closest('[role="row"][data-rh-strike]') as HTMLElement | null;
      if (!row) return;
      const strike = row.getAttribute('data-rh-strike') || '';
      if (!strike) return;
      ev.preventDefault();
      ev.stopPropagation();

      // Toggle: if this strike is already expanded, remove and close.
      const alreadyExpanded = !!host.querySelector('[data-rh-expand-spacer="' + strike + '"]');
      clearExpansion();
      if (alreadyExpanded) {
        const opener = (window as Window & typeof globalThis & { __rhExpandRow?: (d: Record<string, unknown> | null) => void }).__rhExpandRow;
        if (opener) opener(null);
        return;
      }
      const mount = insertSpacersAndMount(strike, row);
      if (!mount) return;

      // Gather row data from the strike's group of sub-rows
      const allRows = host.querySelectorAll<HTMLElement>('[data-rh-strike="' + strike + '"]');
      let askVal = NaN, vol = NaN, oi = NaN, deltaVal = NaN, copVal = NaN;
      for (const r of Array.from(allRows)) {
        for (const c of Array.from(r.querySelectorAll('[data-cell-id]'))) {
          const cid = c.getAttribute('data-cell-id') || '';
          const text = (c.textContent || '').trim();
          if (cid.endsWith('_FOCUSED_CHAIN_PRICE')) {
            const m = text.match(/\$([\d.,]+)/); if (m) askVal = Number(m[1].replace(/,/g, ''));
          } else if (cid.endsWith('_FOCUSED_CHAIN_VOLUME')) {
            const n = Number(text.replace(/,/g, '')); if (Number.isFinite(n)) vol = n;
          } else if (cid.endsWith('_FOCUSED_CHAIN_OPEN_INTEREST')) {
            const n = Number(text.replace(/,/g, '')); if (Number.isFinite(n)) oi = n;
          } else if (cid.endsWith('_FOCUSED_CHAIN_DELTA')) {
            const n = parseFloat(text); if (Number.isFinite(n)) deltaVal = n;
          } else if (cid.endsWith('_FOCUSED_CHAIN_CHANCE_OF_PROFIT')) {
            const m = text.match(/([\d.]+)/); if (m) copVal = Number(m[1]) / 100;
          }
        }
      }

      // Pick the kind/expiration from the chain header context
      const widget = (chainBody.closest('[data-testid^="widget-"]') || document) as HTMLElement;
      let kind: 'call' | 'put' = 'call';
      for (const cb of Array.from(widget.querySelectorAll('button'))) {
        const tt = (cb.textContent || '').trim();
        const sty = cb.getAttribute('style') || '';
        if ((tt === 'Call' || tt === 'Put') && /var\(--colors-neutral-bg2\)/.test(sty)) { kind = tt.toLowerCase() as 'call' | 'put'; break; }
      }
      const sym = detectSymbol(row) || 'STRC';
      const exp = detectExpiration(row) || '5/15';

      // Position the panel at the bottom of the clicked row, spanning chain body width.
      const bodyRect = chainBody.getBoundingClientRect();
      const rowRect = row.getBoundingClientRect();
      // Measure each chain column's width so the panel's Bid/Ask/Mark/Prev/High/Low
      // pairs stack inside the matching column (Robinhood's real layout — Stats
      // doesn't use a 5-col flat grid, it's nested inside the column structure).
      const colWidth = (suffix: string): number => {
        const c = row.querySelector<HTMLElement>('[data-cell-id$="_FOCUSED_CHAIN_' + suffix + '"]');
        return c ? Math.round(c.getBoundingClientRect().width) : 0;
      };
      const cols = {
        toggle: colWidth('TOGGLE'),
        strike: colWidth('STRIKE'),
        volume: colWidth('VOLUME'),
        openInterest: colWidth('OPEN_INTEREST'),
        cop: colWidth('CHANCE_OF_PROFIT'),
        delta: colWidth('DELTA'),
        price: colWidth('PRICE'),
      };
      const opener = (window as Window & typeof globalThis & { __rhExpandRow?: (d: Record<string, unknown> | null) => void }).__rhExpandRow;
      if (typeof opener === 'function') {
        opener({
          symbol: sym, expiration: exp, strike: Number(strike), kind,
          ask: askVal, volume: vol, openInterest: oi, delta: deltaVal, cop: copVal,
          // Portal-mount target — the React component renders INTO this DOM node
          // which is absolutely-positioned inside the chain body so it scrolls
          // naturally with the rows. No JS scroll-sync, no wobble.
          mount,
          width: bodyRect.width,
          height: EXPAND_H,
          cols,
        });
      }
    }, true);
  }

  // Ask pill click → dispatch event so the React shell can open OrderEntryFlyout.
  host.querySelectorAll<HTMLElement>('button[aria-describedby="order-form-flyover"]').forEach((btn) => {
    const b = btn as HTMLElement & { __rhAskWired?: boolean };
    if (b.__rhAskWired) return;
    b.__rhAskWired = true;
    b.addEventListener('click', (ev) => {
      const row = b.closest('[role="row"]') as HTMLElement | null;
      if (!row) return;
      ev.preventDefault();
      ev.stopPropagation();
      markHandled(ev);

      // Pull strike from the gridcell's data-cell-id (encoded as "<strike>_<column>");
      // ask from the clicked button text.
      const askText = (b.textContent || '').trim();
      const askMatch = askText.match(/\$([\d.,]+)/);
      const ask = askMatch ? Number(askMatch[1].replace(/,/g, '')) : NaN;
      const cell = b.closest('[data-cell-id]') as HTMLElement | null;
      const cellId = cell?.getAttribute('data-cell-id') || '';
      const strikeFromCell = parseFloat(cellId.split('_')[0]);
      const strike = Number.isFinite(strikeFromCell) ? strikeFromCell : 0;

      // Kind: detect Call/Put from the chain header toggle ("Call" or "Put" with data-rh-bw-ds--selected)
      // Fall back to "call".
      const chainHeader = (b.closest('[data-testid^="widget-"]') || document).querySelectorAll('button');
      let kind: 'call' | 'put' = 'call';
      for (const cb of Array.from(chainHeader)) {
        const t = (cb.textContent || '').trim();
        const sty = cb.getAttribute('style') || '';
        if ((t === 'Call' || t === 'Put') && /var\(--colors-neutral-bg2\)/.test(sty)) {
          kind = t.toLowerCase() as 'call' | 'put';
          break;
        }
      }
      // Side: same detection for Buy/Sell toggle
      let side: 'buy' | 'sell' = 'buy';
      for (const cb of Array.from(chainHeader)) {
        const t = (cb.textContent || '').trim();
        const sty = cb.getAttribute('style') || '';
        if ((t === 'Buy' || t === 'Sell') && /var\(--colors-neutral-bg2\)/.test(sty)) {
          side = t.toLowerCase() as 'buy' | 'sell';
          break;
        }
      }

      // Mark + bid roughly derive from ask if we can't read them off the row
      const mark = +(ask - 0.05).toFixed(2);
      const bid = +(ask - 0.10).toFixed(2);

      // Mark all rows sharing this strike as selected (purple bg across the
      // full row, not just the one [role=row] under the cursor).
      const chainBody = host.querySelector('[data-testid="focused-chain-body-container"]') as HTMLElement & { __rhMarkSelected?: (s: string) => void } | null;
      if (chainBody?.__rhMarkSelected) chainBody.__rhMarkSelected(String(strike));

      // Ask-pill click opens ONLY the order entry flyout (separate widget to
      // the right). The Simulated Returns view is reached EXCLUSIVELY by
      // clicking the "Simulated Returns" tab.
      const orderOpener = (window as Window & typeof globalThis & { __rhOpenOrderForm?: (d: unknown) => void }).__rhOpenOrderForm;
      if (typeof orderOpener === 'function') {
        orderOpener({ symbol: detectSymbol(b) || 'TSLA', expiration: detectExpiration(b) || '5/15', strike, kind, side, bid, mark, ask });
      }
    }, true);
  });

  // 7b. Per-widget RESIZE handles. Each captured Robinhood widget has a
  // `grid-area: rowStart / colStart / span rowSpan / span colSpan` style.
  // We add right-edge / bottom-edge / corner handles that update the span
  // values on drag, snapping to integer cells (1 cell ≈ 62.5×35.7px + 4px gap).
  const grid = host.querySelector('[data-testid="widget-system-grid"]') as HTMLElement | null;
  if (grid) {
    type RhWidget = HTMLElement & { __rhResizeWired?: boolean };
    const parseArea = (w: HTMLElement): { rowStart: number; colStart: number; rowSpan: number; colSpan: number } | null => {
      const m = (w.style.gridArea || '').match(/^(\d+)\s*\/\s*(\d+)\s*\/\s*span\s*(\d+)\s*\/\s*span\s*(\d+)$/);
      if (!m) return null;
      return { rowStart: +m[1], colStart: +m[2], rowSpan: +m[3], colSpan: +m[4] };
    };
    const setArea = (w: HTMLElement, a: { rowStart: number; colStart: number; rowSpan: number; colSpan: number }) => {
      w.style.gridArea = a.rowStart + ' / ' + a.colStart + ' / span ' + a.rowSpan + ' / span ' + a.colSpan;
    };
    const cellSize = (): { w: number; h: number; gap: number } => {
      const cs = getComputedStyle(grid);
      const cols = cs.gridTemplateColumns.split(/\s+/).filter(Boolean);
      const rows = cs.gridTemplateRows.split(/\s+/).filter(Boolean);
      const w = cols.length ? parseFloat(cols[0]) : 62.5;
      const h = rows.length ? parseFloat(rows[0]) : 35.7;
      const gap = parseFloat(cs.gap) || 4;
      return { w, h, gap };
    };
    const wireResize = (handle: HTMLElement, widget: HTMLElement, axis: 'x' | 'y' | 'xy') => {
      handle.addEventListener('pointerdown', (ev) => {
        const target = ev.currentTarget as HTMLElement;
        target.setPointerCapture(ev.pointerId);
        ev.preventDefault();
        ev.stopPropagation();
        const startArea = parseArea(widget);
        if (!startArea) return;
        const startX = ev.clientX;
        const startY = ev.clientY;
        const { w: cellW, h: cellH, gap } = cellSize();
        const stepX = cellW + gap;
        const stepY = cellH + gap;
        const onMove = (e: PointerEvent) => {
          const dCol = Math.round((e.clientX - startX) / stepX);
          const dRow = Math.round((e.clientY - startY) / stepY);
          const next = { ...startArea };
          if (axis === 'x' || axis === 'xy') next.colSpan = Math.max(2, Math.min(24 - startArea.colStart + 1, startArea.colSpan + dCol));
          if (axis === 'y' || axis === 'xy') next.rowSpan = Math.max(2, startArea.rowSpan + dRow);
          setArea(widget, next);
        };
        const onUp = (e: PointerEvent) => {
          target.releasePointerCapture(e.pointerId);
          target.removeEventListener('pointermove', onMove);
          target.removeEventListener('pointerup', onUp);
        };
        target.addEventListener('pointermove', onMove);
        target.addEventListener('pointerup', onUp);
      });
    };
    for (const w of Array.from(grid.querySelectorAll<HTMLElement>('[data-testid^="widget-"]'))) {
      const rw = w as RhWidget;
      if (rw.__rhResizeWired) continue;
      if (!parseArea(w)) continue;
      rw.__rhResizeWired = true;
      w.style.position = w.style.position || 'relative';
      const mkHandle = (cssOverrides: string, axis: 'x' | 'y' | 'xy', title: string) => {
        const h = document.createElement('div');
        h.setAttribute('data-rh-resize-handle', axis);
        h.title = title;
        h.style.cssText = 'position:absolute;background:transparent;z-index:50;transition:background-color 150ms cubic-bezier(0.05,0.39,0.42,0.94);' + cssOverrides;
        h.addEventListener('pointerenter', () => { h.style.backgroundColor = 'rgba(135,97,236,0.35)'; });
        h.addEventListener('pointerleave', () => { h.style.backgroundColor = 'transparent'; });
        wireResize(h, w, axis);
        w.appendChild(h);
        return h;
      };
      // Right edge — ew-resize
      mkHandle('top:8px;right:-3px;bottom:8px;width:6px;cursor:ew-resize;', 'x', 'Drag to resize width');
      // Bottom edge — ns-resize
      mkHandle('left:8px;right:8px;bottom:-3px;height:6px;cursor:ns-resize;', 'y', 'Drag to resize height');
      // Bottom-right corner — nwse-resize
      mkHandle('right:-3px;bottom:-3px;width:14px;height:14px;cursor:nwse-resize;border-radius:0 0 4px 0;', 'xy', 'Drag to resize');
    }
  }

  // 8. Generic icon-button polish — give iconButtons rounded hover bg
  host.querySelectorAll<HTMLElement>('button[class*="cursor_pointer"]').forEach((btn) => {
    const b = btn as HTMLElement & { __rhBtnHoverWired?: boolean };
    if (b.__rhBtnHoverWired) return;
    b.__rhBtnHoverWired = true;
    let prevBg = '';
    b.addEventListener('pointerenter', () => {
      prevBg = b.style.backgroundColor;
      if (!prevBg || /transparent/.test(prevBg)) {
        b.style.transition = 'background-color 200ms cubic-bezier(0.05, 0.39, 0.42, 0.94)';
        b.style.backgroundColor = 'var(--colors-neutral-bg2, rgba(255,255,255,.08))';
      }
    }, true);
    b.addEventListener('pointerleave', () => {
      if (b.style.backgroundColor === 'var(--colors-neutral-bg2, rgba(255,255,255,.08))') {
        b.style.backgroundColor = prevBg;
      }
    }, true);
  });
}

export function LegendApp({ layoutId }: { layoutId: string }) {
  const ref = useRef<HTMLDivElement | null>(null);
  const rootsRef = useRef<Root[]>([]);
  const [seq, setSeq] = useState<number>(STATES[0]?.seq ?? 1);
  const [orderForm, setOrderForm] = useState<OrderFormData | null>(null);
  const [expandedRow, setExpandedRow] = useState<ExpandRowData | null>(null);
  const [simReturns, setSimReturns] = useState<{ rect: { top: number; left: number; width: number; height: number }; spot: number; mount: HTMLElement } | null>(null);
  // Track latest value in a ref so the imperative bridge can toggle without
  // using a state-updater function (StrictMode would double-invoke that and
  // re-open immediately after closing).
  const expandedRowRef = useRef<ExpandRowData | null>(null);
  useEffect(() => { expandedRowRef.current = expandedRow; }, [expandedRow]);

  // Expose imperative openers used by wireInteractivity in this file.
  useEffect(() => {
    type Win = Window & typeof globalThis & {
      __rhOpenOrderForm?: (d: OrderFormData) => void;
      __rhExpandRow?: (d: ExpandRowData | null) => void;
      __rhSetSimReturns?: (v: boolean) => void;
    };
    (window as Win).__rhOpenOrderForm = (d: OrderFormData) => setOrderForm(d);
    (window as Win).__rhExpandRow = (d: ExpandRowData | null) => {
      const cur = expandedRowRef.current;
      if (d == null) { setExpandedRow(null); return; }
      setExpandedRow(cur && cur.strike === d.strike ? null : d);
    };
    (window as Win).__rhSetSimReturns = (v: boolean) => {
      // Sync the Chain / Simulated Returns segmented-control highlight to match
      // the active view. Robinhood encodes selection via data-selected /
      // data-disabled on the <label> plus inline bg/color/font-weight; mirror it.
      const tabLabels = Array.from(ref.current?.querySelectorAll<HTMLLabelElement>('label') || [])
        .filter((l) => {
          const t = (l.textContent || '').trim();
          return t === 'Chain' || t === 'Simulated Returns';
        });
      for (const lbl of tabLabels) {
        const txt = (lbl.textContent || '').trim();
        const active = (txt === 'Simulated Returns') === v;
        if (active) {
          lbl.setAttribute('data-selected', 'true');
          lbl.removeAttribute('data-disabled');
          lbl.style.background = 'var(--colors-neutral-bg3)';
        } else {
          lbl.removeAttribute('data-selected');
          lbl.setAttribute('data-disabled', 'true');
          lbl.style.background = 'var(--colors-neutral-transparent)';
        }
        // The label has two child spans; the second is the visible text.
        const visibleSpan = Array.from(lbl.querySelectorAll('span'))
          .find((s) => (s.textContent || '').trim() === txt) as HTMLElement | undefined;
        if (visibleSpan) {
          visibleSpan.style.color = active ? 'var(--colors-neutral-fg1)' : 'var(--colors-neutral-fg3)';
          visibleSpan.style.fontWeight = active ? '700' : '400';
        }
        // The hidden radio reflects the same state.
        const radio = lbl.querySelector('input[type="radio"]') as HTMLInputElement | null;
        if (radio) {
          radio.checked = active;
          radio.disabled = false;
        }
      }
      // Always tear down any prior mount before opening/closing so we don't leak.
      ref.current?.querySelectorAll('[data-rh-sr-mount]').forEach((el) => el.remove());
      // Restore any chain-chrome elements we previously hid.
      ref.current?.querySelectorAll('[data-rh-sr-hidden]').forEach((el) => {
        (el as HTMLElement).style.display = (el as HTMLElement).dataset.rhSrPrevDisplay || '';
        el.removeAttribute('data-rh-sr-hidden');
        delete (el as HTMLElement).dataset.rhSrPrevDisplay;
      });
      // Restore chain body's overflow.
      const cbRestore = ref.current?.querySelector('[data-testid="focused-chain-body-container"]') as HTMLElement | null;
      if (cbRestore && cbRestore.dataset.rhSrPrevOverflow !== undefined) {
        cbRestore.style.overflow = cbRestore.dataset.rhSrPrevOverflow;
        delete cbRestore.dataset.rhSrPrevOverflow;
      }
      if (!v) { setSimReturns(null); return; }
      const cb = ref.current?.querySelector('[data-testid="focused-chain-body-container"]') as HTMLElement | null;
      const widget = cb?.closest('[data-testid^="widget-"]') as HTMLElement | null;
      if (!cb || !widget) return;
      // Close any open chain-row expansion — its spacer divs + portal mount
      // would otherwise sit beneath the SR overlay.
      ref.current?.querySelectorAll('[data-rh-expand-spacer]').forEach((s) => s.remove());
      ref.current?.querySelectorAll('[data-rh-expand-mount]').forEach((s) => s.remove());
      setExpandedRow(null);
      cb.style.position = cb.style.position || 'relative';
      // Hide the Buy/Sell + Call/Put + Exp toolbar AND the Strike/Vol/OI column
      // header row — both belong to the chain view and don't apply to SR.
      const toHide: HTMLElement[] = [];
      for (const el of Array.from(widget.querySelectorAll<HTMLElement>('div'))) {
        const t = (el.textContent || '').replace(/\s+/g, ' ').trim();
        if (/^BuySellCallPut/.test(t) && el.getBoundingClientRect().height < 80) { toHide.push(el); break; }
      }
      const colHeaderRow = widget.querySelector<HTMLElement>('[role="row"]:has([role="columnheader"])') ||
                           Array.from(widget.querySelectorAll<HTMLElement>('[role="row"]'))
                             .find((r) => r.querySelector('[role="columnheader"]'));
      if (colHeaderRow) toHide.push(colHeaderRow);
      // ALSO hide every chain row + spot-price separator that lives below the
      // header — otherwise the chain body keeps its scroll-height and the user
      // can scroll past the SR overlay to see them.
      for (const r of Array.from(cb.querySelectorAll<HTMLElement>('[role="row"], [data-rh-strike]'))) {
        toHide.push(r);
      }
      // Spot-price separator pill (the "$100.00" pill that marks the current
      // underlying price among the chain rows). Walk up the DOM to the pill's
      // outermost styled container so we hide the rounded background too, not
      // just the text inside it.
      for (const el of Array.from(cb.querySelectorAll<HTMLElement>('span'))) {
        if (el.closest('[data-rh-sr-mount]')) continue;
        const t = (el.textContent || '').trim();
        if (!/^\$[\d,]+\.?\d*$/.test(t)) continue;
        // Climb up while the parent has roughly the same bounding rect (these
        // are the pill's wrapper layers). Stop when we'd escape the chain body.
        let cur: HTMLElement = el;
        const startR = el.getBoundingClientRect();
        while (cur.parentElement && cur.parentElement !== cb) {
          const pr = cur.parentElement.getBoundingClientRect();
          if (pr.width > startR.width * 4 || pr.height > startR.height * 4) break;
          cur = cur.parentElement;
        }
        toHide.push(cur);
      }
      for (const el of toHide) {
        if (el.hasAttribute('data-rh-sr-hidden')) continue;
        el.dataset.rhSrPrevDisplay = el.style.display || '';
        el.setAttribute('data-rh-sr-hidden', '1');
        el.style.display = 'none';
      }
      // Also lock chain body scroll while SR is open.
      (cb as HTMLElement & { dataset: DOMStringMap }).dataset.rhSrPrevOverflow = cb.style.overflow || '';
      cb.style.overflow = 'hidden';
      cb.scrollTop = 0;
      const mount = document.createElement('div');
      mount.setAttribute('data-rh-sr-mount', '1');
      // Transparent — let the widget's own chrome bg show through so the SR
      // panel matches the rest of the options widget.
      mount.style.cssText = 'position:absolute;inset:0;background:transparent;z-index:6;overflow:hidden;';
      cb.appendChild(mount);
      // Pull the actual underlying spot price from the chain widget header.
      let spot = 100;
      const marquee = widget.querySelector('[data-testid="instrument-marquee-button"]') as HTMLElement | null;
      const ticker  = marquee?.nextElementSibling as HTMLElement | null;
      const scanText = (ticker?.textContent || widget.textContent || '').replace(/\s+/g, ' ');
      const m = scanText.match(/\$([\d,]+\.?\d*)/);
      if (m) {
        const n = Number(m[1].replace(/,/g, ''));
        if (Number.isFinite(n) && n > 0) spot = n;
      }
      // Keep the rect for the order-flyover anchor — measured from the widget
      // itself, no longer used for SR positioning.
      const wRect = widget.getBoundingClientRect();
      const topAnchor = wRect.top + 40;
      setSimReturns({ rect: { top: topAnchor, left: wRect.left, width: wRect.width, height: wRect.bottom - topAnchor }, spot, mount });
    };
    return () => {
      delete (window as Win).__rhOpenOrderForm;
      delete (window as Win).__rhExpandRow;
      delete (window as Win).__rhSetSimReturns;
    };
  }, []);

  // Initial mount: write the captured HTML imperatively, then mount charts +
  // wire interactivity. We do NOT use dangerouslySetInnerHTML because React
  // re-applies it on every parent re-render (the {__html:INITIAL_HTML} prop is
  // a new object each render), wiping all our attribute/listener additions.
  useEffect(() => {
    const host = ref.current;
    if (!host) return;
    if (!host.firstChild) host.innerHTML = INITIAL_HTML;
    rootsRef.current.forEach((r) => queueMicrotask(() => r.unmount()));
    rootsRef.current = [];
    mountCharts(host, rootsRef.current);
    wireInteractivity(host);
    return () => { rootsRef.current.forEach((r) => queueMicrotask(() => r.unmount())); };
  }, []);

  const applyState = useCallback(async (s: StateRec) => {
    const host = ref.current;
    if (!host) return;
    const resp = await fetch('/captures/' + s.sid + '/' + s.dir + '/shell.html', { cache: 'force-cache' });
    const html = await resp.text();
    rootsRef.current.forEach((r) => queueMicrotask(() => r.unmount()));
    rootsRef.current = [];
    host.innerHTML = html;
    mountCharts(host, rootsRef.current);
    wireInteractivity(host);
    setSeq(s.seq);
  }, []);

  // Apply a sequence of frames captured for one click event. No opacity fade
  // — that was making transitions feel like page reloads.
  const swapToSequence = useCallback(async (frames: StateRec[]) => {
    if (frames.length === 0) return;
    const offsets = [0, 160, 330];
    await applyState(frames[0]);
    for (let i = 1; i < frames.length; i++) {
      await new Promise((r) => setTimeout(r, offsets[i] || 200));
      await applyState(frames[i]);
    }
  }, [applyState]);

  // Click-driven state navigation is intentionally DISABLED for now. Replaying
  // captured frames swaps host.innerHTML up to three times in quick succession,
  // which combined with re-wiring + chart re-mount felt like a refresh.
  // The Ask pill flyout and chain row highlight are wired imperatively in
  // wireInteractivity; everything else is a no-op until we rebuild widgets.
  const onClick = useCallback((_ev: React.MouseEvent<HTMLDivElement>) => {
    // intentional no-op
  }, []);
  // Silence unused-var TS errors for retained machinery (state graph etc).
  void swapToSequence; void applyState; void seq;

  // Hover navigation is intentionally DISABLED. Re-applying a captured state on
  // hover replaces the entire host.innerHTML, and the new DOM is itself a
  // hover target — so cursor parked anywhere causes a thrashing swap loop that
  // feels like the page is refreshing. All interactivity now comes from the
  // imperative wire-up (chain row highlight, Ask pill → flyout) or explicit
  // clicks below.

  // Block real navigation inside the captured DOM — <a href> links would
  // otherwise actually leave the page, looking like a "refresh" bug.
  const onClickCapture = useCallback((ev: React.MouseEvent<HTMLDivElement>) => {
    const a = (ev.target as HTMLElement).closest('a[href]') as HTMLAnchorElement | null;
    if (a) { ev.preventDefault(); ev.stopPropagation(); }
  }, []);
  const onSubmitCapture = useCallback((ev: React.FormEvent<HTMLDivElement>) => {
    ev.preventDefault();
  }, []);

  return (
    <>
      <div
        ref={ref}
        data-layout-id={layoutId}
        data-state-seq={seq}
        onClickCapture={onClickCapture}
        onClick={onClick}
        onSubmitCapture={onSubmitCapture}
        style={{ width: '100vw', height: '100vh' }}
      />
      {expandedRow && <ChainRowDetails {...expandedRow} />}
      {/* SR widget — REPLACES the chain body content (sits inside the chain
          widget where the rows normally are). Rounded corners + gray bg match
          the widget chrome. */}
      {simReturns && createPortal(
        <SimulatedReturns
          symbol={orderForm?.symbol || 'STRC'}
          spot={simReturns.spot}
          strike={orderForm?.strike ?? expandedRow?.strike ?? simReturns.spot}
          kind={orderForm?.kind ?? expandedRow?.kind ?? 'call'}
          premium={orderForm?.ask ?? expandedRow?.ask ?? 4.9}
          quantity={1}
          dte={14}
          iv={0.5}
        />,
        simReturns.mount,
      )}
      {/* Order entry — SEPARATE widget panel, floats to the right of the chain
          widget with a gap. Rounded corners, drop shadow, own gray bg. */}
      {orderForm && (() => {
        const GAP = 16;
        const FLYOUT_W = 320;
        // Measure the chain widget on every render — works whether SR is open
        // or not. Falls back to safe constants if the widget can't be found.
        let chainLeft = 100, chainTop = 100, chainW = 526, FLYOUT_H = 540;
        if (simReturns) {
          chainLeft = simReturns.rect.left;
          chainTop  = simReturns.rect.top;
          chainW    = simReturns.rect.width;
          FLYOUT_H  = simReturns.rect.height;
        } else if (typeof window !== 'undefined' && ref.current) {
          const cb = ref.current.querySelector('[data-testid="focused-chain-body-container"]') as HTMLElement | null;
          const widget = cb?.closest('[data-testid^="widget-"]') as HTMLElement | null;
          if (widget) {
            const wr = widget.getBoundingClientRect();
            chainLeft = wr.left; chainTop = wr.top; chainW = wr.width;
            FLYOUT_H = Math.max(540, wr.height);
          }
        }
        let left = chainLeft + chainW + GAP;
        if (left + FLYOUT_W > window.innerWidth - 8) left = Math.max(8, chainLeft - GAP - FLYOUT_W);
        return (
          <div
            style={{
              position: 'fixed',
              top: chainTop,
              left,
              width: FLYOUT_W,
              maxHeight: FLYOUT_H,
              background: '#202020d9',
              backdropFilter: 'blur(15px)',
              WebkitBackdropFilter: 'blur(15px)',
              borderRadius: 8,
              border: '1px solid rgba(255,255,255,.06)',
              boxShadow: '0 12px 32px rgba(0,0,0,.45)',
              zIndex: 26,
              overflow: 'auto',
            }}
          >
            <OrderEntryFlyout
              symbol={orderForm.symbol}
              expiration={orderForm.expiration}
              strike={orderForm.strike}
              kind={orderForm.kind}
              bid={orderForm.bid}
              mark={orderForm.mark}
              ask={orderForm.ask}
              initialSide={orderForm.side}
              buyingPower={2}
              onCancel={() => setOrderForm(null)}
              onSubmit={(o) => { console.log('[order] submit', o); setOrderForm(null); }}
            />
          </div>
        );
      })()}
    </>
  );
}
